Use ASP.NET Core's `WebApplicationFactory<TEntryPoint>` — it hosts your app in-memory and gives you an `HttpClient` without opening a real port. Then pass that client to the MCP C# SDK's `StreamableHttpClientTransport`.

**1. Add packages to your test project:**

```xml
<PackageReference Include="Microsoft.AspNetCore.Mvc.Testing" Version="9.*" />
<PackageReference Include="ModelContextProtocol" Version="0.*" />
```

**2. Write the test:**

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using ModelContextProtocol.Client;
using ModelContextProtocol.Protocol.Transport;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly WebApplicationFactory<Program> _factory;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
        => _factory = factory;

    [Fact]
    public async Task ListTools_ReturnsExpectedTools()
    {
        // The factory's HttpClient talks to the in-memory server
        var httpClient = _factory.CreateClient();

        // Point the MCP transport at the in-memory server
        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/mcp"),
                // or wherever your MCP endpoint is mapped
            },
            httpClient);               // ← key: reuse the factory's client

        await using var mcpClient =
            await McpClientFactory.CreateAsync(transport);

        var tools = await mcpClient.ListToolsAsync();

        Assert.NotEmpty(tools);
        Assert.Contains(tools, t => t.Name == "my-tool");
    }

    [Fact]
    public async Task CallTool_ReturnsCorrectResult()
    {
        var httpClient = _factory.CreateClient();
        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/mcp"),
            },
            httpClient);

        await using var mcpClient =
            await McpClientFactory.CreateAsync(transport);

        var result = await mcpClient.CallToolAsync(
            "my-tool",
            new Dictionary<string, object?> { ["input"] = "hello" });

        Assert.False(result.IsError);
        Assert.Contains("expected-output", result.Content[0].Text);
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` hosts Kestrel in-memory; the `HttpClient` it creates uses an internal handler.
- **Full pipeline** — middleware, routing, DI, auth — everything runs exactly as in production.
- **`SseClientTransport`** accepts an existing `HttpClient`, so you inject the factory's client to route traffic in-process.
- If your SDK version offers `StreamableHttpClientTransport`, use that instead (same pattern — it also accepts an `HttpClient`).
- Make sure your `Program` class is accessible to the test project (`InternalsVisibleTo` or a `public partial class Program { }` stub).
